mapper.select:
SELECT id, title, category, description, original_file_name, stored_file_name, file_url, file_extension, mime_type, file_size, file_hash, storage_provider, parse_status, index_status, error_message, access_scope, access_department_id, min_role_level, status, version, uploader_id, create_time, update_time FROM oa_ai_source
AND title LIKE CONCAT('%', #{title}, '%') AND category = #{category} AND status = #{status} AND uploader_id = #{uploaderId}
ORDER BY create_time DESC

mapper.update:
UPDATE oa_ai_source
title = #{title}, category = #{category}, description = #{description}, parse_status = #{parseStatus}, index_status = #{indexStatus}, error_message = #{errorMessage}, access_scope = #{accessScope}, access_department_id = #{accessDepartmentId}, min_role_level = #{minRoleLevel}, status = #{status}, version = #{version}, extracted_text = #{extractedText}, error_message = NULL, update_time = NOW()
WHERE id = #{id}

mapper.select:
SELECT id, title, version, access_scope, access_department_id, min_role_level FROM oa_ai_source WHERE id IN
#{id}
AND status = 'ENABLED' AND parse_status = 'SUCCESS' AND index_status = 'SUCCESS' AND ( #{requestRole} = 'SUPER_ADMIN' OR ( #{requestRoleLevel} >= min_role_level AND ( access_scope = 'ALL' OR ( access_scope = 'DEPARTMENT' AND FIND_IN_SET(#{requestDepartmentId}, access_department_id) > 0 ) ) ) )
